// ═══════════════════════════════════════════════════
// MERGE & NORMALIZE LEAD DATA
// ═══════════════════════════════════════════════════
// Combines Apollo data + LinkedIn enrichment into one
// clean, consistent lead object.
//
// If LinkedIn returned no data (private profile, rate
// limit, etc.) we fall back to Apollo fields only.
// The AI scoring still works — it just has less data.
// ═══════════════════════════════════════════════════

const item = $input.first().json;
const li = item.data || {};

const lead = {
  first_name:          item.first_name || li.firstName || 'Unknown',
  last_name:           item.last_name  || li.lastName  || '',
  current_role:        item.title      || li.headline  || item.current_role || '',
  current_company:     item.organization_name || (li.position?.[0]?.companyName) || item.current_company || '',
  industry:            item.industry   || li.industryName || '',
  linkedin_url:        item.linkedin_url || '',
  email:               item.email || '',
  headline:            li.headline || item.headline || item.title || '',
  experience_summary:  (
    li.summary ||
    (li.position?.slice(0,2).map(p => `${p.title} at ${p.companyName}`).join('; ')) ||
    item.experience_summary ||
    ''
  ),
  recent_activity: (
    (li.posts?.slice(0,1).map(p => p.text?.substring(0,300)).join(' ')) ||
    item.recent_activity ||
    'No recent activity data available'
  ),
  skills: (
    (li.skills?.slice(0,10).map(s => s.name || s).join(', ')) ||
    item.skills ||
    ''
  ),
  connection_count: li.connectionsCount || 0,
  enrichment_source: li.firstName ? 'apollo+linkedin' : 'apollo_only'
};

return [{ json: lead }];

// ═══════════════════════════════════════════════════
// PARSE AI SCORE
// ═══════════════════════════════════════════════════
// Extracts the score JSON from Claude's response.
// Handles edge cases:
//   - Model wraps output in ```json ... ``` fences
//   - Model adds extra explanation text
//   - JSON is malformed (uses regex fallback)
// Merges score data back into the lead object.
// ═══════════════════════════════════════════════════

const response = $input.first().json;
const text = response?.content?.[0]?.text || '';

if (!text) throw new Error('Claude returned empty response for scoring');

// Strip markdown fences if present
const cleaned = text.replace(/```json|```/g, '').trim();

let score;
try {
  score = JSON.parse(cleaned);
} catch (e) {
  const match = cleaned.match(/\{[\s\S]*\}/);
  if (match) {
    score = JSON.parse(match[0]);
  } else {
    throw new Error(`Could not parse score JSON. Claude said: ${cleaned.substring(0, 200)}`);
  }
}

// Pull the lead data from the upstream node
const lead = $('🔀 Merge & Normalize Lead Data').first().json;

return [{ json: {
  ...lead,
  score:            Number(score.score)           || 0,
  role_relevance:   Number(score.role_relevance)   || 0,
  datastax_depth:   Number(score.datastax_depth)   || 0,
  seniority:        Number(score.seniority)        || 0,
  activity_recency: Number(score.activity_recency) || 0,
  reasoning:        score.reasoning                || ''
}}];

