// ═══════════════════════════════════════════════════
// COMBINE ALL MESSAGES INTO FINAL LEAD RECORD
// ═══════════════════════════════════════════════════
// Merges: lead profile + score + LinkedIn invite + email
// into one complete record ready for logging.
//
// Status is always 'simulated' — this is a dry run.
// Nothing is sent. Everything is logged.
// ═══════════════════════════════════════════════════

const emailResponse = $input.first().json;
const emailRaw = emailResponse?.content?.[0]?.text?.trim() || '{}';

let emailData = { subject: '', body: '' };
try {
  emailData = JSON.parse(emailRaw.replace(/```json|```/g, '').trim());
} catch (e) {
  // Regex fallback for malformed JSON
  const subjectMatch = emailRaw.match(/"subject":\s*"([^"]+)"/);
  const bodyMatch    = emailRaw.match(/"body":\s*"([\s\S]+?)"\s*\}/);
  emailData = {
    subject: subjectMatch?.[1] || '(subject parsing failed)',
    body:    bodyMatch?.[1]?.replace(/\\n/g, '\n') || emailRaw
  };
}

const lead = $('📝 Parse LinkedIn Invite').first().json;

return [{ json: {
  ...lead,
  email_subject: emailData.subject || '',
  email_body:    emailData.body    || '',
  status:        'simulated',
  run_timestamp: new Date().toISOString()
}}];

// ═══════════════════════════════════════════════════
// DRY RUN LOGGER
// ═══════════════════════════════════════════════════
// Formats a human-readable simulation log showing
// exactly what WOULD have been sent to this person
// if we were running in production mode.
//
// This output appears in:
//   1. The n8n execution log (click this node after run)
//   2. The item data flowing to the Report node
// ═══════════════════════════════════════════════════

const lead = $input.first().json;

const divider = '═'.repeat(60);
const line    = '─'.repeat(60);

const logEntry = `
${divider}
🎯 DRY RUN — SIMULATED OUTREACH
${divider}
📋 LEAD
   Name:    ${lead.first_name} ${lead.last_name}
   Role:    ${lead.current_role} at ${lead.current_company}
   Industry:${lead.industry}
   LinkedIn:${lead.linkedin_url}
${line}
📊 AI SCORE: ${lead.score}/100
   Role Relevance:   ${lead.role_relevance}/30
   DataStax Depth:   ${lead.datastax_depth}/30
   Seniority:        ${lead.seniority}/20
   Activity Recency: ${lead.activity_recency}/20
   Reasoning: ${lead.reasoning}
${line}
💬 LINKEDIN INVITE (${lead.linkedin_invite?.length || 0} chars / 300 max)
${lead.linkedin_invite || '(not generated)'}
${line}
📧 FOLLOW-UP EMAIL
   Subject: ${lead.email_subject || '(not generated)'}

${lead.email_body || '(not generated)'}
${line}
✅ STATUS: ${lead.status?.toUpperCase()} — no real message sent
   Logged at: ${lead.run_timestamp}
${divider}
`;

console.log(logEntry);

return [{ json: { ...lead, dry_run_log: logEntry } }];

// ═══════════════════════════════════════════════════
// CAMPAIGN REPORT GENERATOR
// ═══════════════════════════════════════════════════
// Runs after all leads are processed.
// Reads qualified + skipped leads and produces a
// complete funnel summary as JSON.
//
// This report is visible in the n8n execution log
// and is returned as the final workflow output.
// ═══════════════════════════════════════════════════

const qualifiedItems = $('🖨️ Dry Run Logger').all();
const skippedItems   = $('🚫 Log Skipped Lead → Google Sheets').all();

const totalQualified = qualifiedItems.length;
const totalSkipped   = skippedItems.length;
const totalDiscovered = totalQualified + totalSkipped;

const avgScore = totalQualified > 0
  ? (qualifiedItems.reduce((s, i) => s + (i.json.score || 0), 0) / totalQualified).toFixed(1)
  : 0;

const topLeads = [...qualifiedItems]
  .sort((a, b) => b.json.score - a.json.score)
  .slice(0, 3)
  .map(i => ({
    name:    `${i.json.first_name} ${i.json.last_name}`,
    company: i.json.current_company,
    role:    i.json.current_role,
    score:   i.json.score
  }));

const skippedReasons = skippedItems.map(i => ({
  name:      `${i.json.first_name} ${i.json.last_name}`,
  role:      i.json.current_role,
  score:     i.json.score,
  reasoning: i.json.reasoning
}));

const report = {
  campaign:      'ScyllaDB GTM Hunter',
  generated_at:  new Date().toISOString(),
  mode:          'DRY RUN — simulated, no real messages sent',
  target:        'DataStax / Apache Cassandra users',
  funnel: {
    total_leads_discovered:  totalDiscovered,
    total_qualified:         totalQualified,
    total_skipped:           totalSkipped,
    qualification_rate:      totalDiscovered > 0
                               ? ((totalQualified / totalDiscovered) * 100).toFixed(1) + '%'
                               : '0%'
  },
  outreach_simulated: {
    linkedin_invites:        totalQualified,
    follow_up_emails:        totalQualified,
    total_messages:          totalQualified * 2,
    delivery_status:         'SIMULATED — logged to Google Sheets only'
  },
  quality_metrics: {
    average_score_qualified: parseFloat(avgScore),
    score_threshold:         50,
    top_3_leads:             topLeads
  },
  filtered_out: skippedReasons,
  next_steps: [
    'Review qualified leads in Google Sheets Campaign Log tab',
    'Read dry_run_log field in each node execution for full message preview',
    'Approve messages and connect a real sending node (LinkedIn API / email) to go live',
    'Consider migrating from Google Sheets to ScyllaDB for runs over 500 leads'
  ]
};

console.log('\n📋 CAMPAIGN REPORT\n' + JSON.stringify(report, null, 2));

return [{ json: report }];
